import React from "react"
import { Container, Card } from "react-bootstrap"

import "../styles/index.css"
import Header from "../components/header"
import Footer from "../components/footer"
import iconImage from "../images/icon.jpg"
import headerImage from "../images/header.jpg"
import backgroundImage from "../images/background.jpg"

import {FaBook,FaEnvelope,} from "react-icons/fa"
import { FaXTwitter } from "react-icons/fa6"
import { SiPixiv,SiNote } from "react-icons/si"

const links = [
  {
    name: "X (Twitter)",
    url: "https://x.com/nogisu0314",
    icon: FaXTwitter,
  },
  {
    name: "Pixiv",
    url: "https://www.pixiv.net/users/111340282",
    icon: SiPixiv,
  },
  {
    name: "メロンブックス",
    url: "https://www.melonbooks.co.jp/circle/index.php?circle_id=133687",
    icon: FaBook
  },
  {
    name: "note",
    url: "https://note.com/nogisu0314",
    icon: SiNote
  },
  {
    name: "Email",
    url: "mailto:nogisu0314@gmail.com",
    icon: FaEnvelope,
  },
]


export default function Home() {
  return (
    <>
      <Header/>
      <div
        className="bg-image"
        style={{
          backgroundImage: `url(${backgroundImage})`,
        }}
      />
      <Container className="py-5">
        <Card className="shadow-sm bg-light">

          {/* ヘッダー画像 */}
          <div
            style={{
            backgroundImage: `url(${headerImage})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            aspectRatio: "3 / 1",
            width: "100%",
          }}
        />

          <Card.Body> 
            <div className="text-center d-flex flex-column align-items-center">
              {/* アイコン */}
              <img
                src={iconImage}
                alt="icon"
                style={{
                  width: "140px",
                  height: "140px",
                  objectFit: "cover",
                  borderRadius: "50%",
                  border: "4px solid white",
                  marginTop: "-90px",
                }}
              />
              <h2 className="mt-3">ひらめ</h2>
              <p className="text-muted text-center">小説 / 痛車</p>
            </div>

            <hr style={{opacity: 0.8,}}/>

            <div>
              <h4 className="text-start">自己紹介</h4>
              <p className="text-start">
                ブルーアーカイブが好きです<br />
                小説を書いたり痛車に乗ったり、ぬい活をしたりしています。<br/>
                同人サークル「ひらめの煮付け」
              </p>
            </div>

            


          </Card.Body>
        </Card>
        <Card className="mt-4 bg-light">
          <Card.Body>
            <h4 className="text-start">リンク</h4>

            {links.map((link) => {
              const Icon = link.icon

              return (
                <Card
                  key={link.name}
                  as="a"
                  href={link.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="mt-3 text-decoration-none link-card bg-light hover-shadow"
                >
                  <Card.Body className="d-flex align-items-center">
                    <Icon size={24} className="me-3" />
                    <span>{link.name}</span>
                  </Card.Body>
                </Card>
              )
            })}
          </Card.Body>
        </Card>
      </Container>
      <Footer/>
    </>
  )
}